    getPaymentStatus,
    refundPayment,
    clientLogout,

    // �📝 Consents
    logConsents,
    logConsentsBySession,
    checkRequiredConsents,
    checkRequiredConsentsBySession,
    revokeConsent,
    revokeConsentBySession,
    purgeHealthData,
    deleteMyAccount,
    // 🆕 Compliance overhaul 2026-05-20
