      cold_p95: +p(samples.cold, 0.95).toFixed(3),
      warm_p50: +p(samples.warm, 0.5).toFixed(3),
      warm_p95: +p(samples.warm, 0.95).toFixed(3),
      gate_cold_ok: p(samples.cold, 0.95) < 5,
      gate_warm_ok: p(samples.warm, 0.95) < 0.1,
