  try {
    if (HEYS.flags?.isEnabled?.('dev_module_logging')) {
      console.info('[OverlayStore] loaded (flag overlay_products_v2:', HEYS.flags?.isEnabled?.('overlay_products_v2'), ')');
    }
  } catch (_) { /* noop */ }

